import{c as t}from"./DffLFeIZ.js";const o={async listZones(){return(await t.get("/geofencing/zones")).data},async createZone(e){return(await t.post("/geofencing/zones",e)).data},async updateZone(e,a){return(await t.patch(`/geofencing/zones/${e}`,a)).data},async deleteZone(e){return(await t.delete(`/geofencing/zones/${e}`)).data},async listActiveZones(){return(await t.get("/geofencing/zones/public")).data},async submitPatientProof(e){return(await t.post("/geofencing/patient-proof",e)).data},async getProofStatus(e){return(await t.get(`/geofencing/patient-proof/${e}/status`)).data}};export{o as g};
